#include "controller.h"

#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

static bool controller_has_both_sensors_valid(const controller_t *controller, uint32_t now_ms)
{
    if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        return false;
    }
    if ((now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return false;
    }
    if ((now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return false;
    }
    return true;
}

static bool controller_is_level_sufficient(const controller_t *controller)
{
    return controller->has_valid_level && 
           (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL);
}

static bool controller_is_level_below_complete_threshold(const controller_t *controller)
{
    return controller->has_valid_level && 
           (controller->last_level < CONTROLLER_COMPLETE_LEVEL);
}

static void controller_enter_filtering(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = true;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_FILTERING;
    controller->clear_streak_count = 0;
}

static void controller_enter_settling(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SETTLING;
    controller->settling_started_ms = now_ms;
}

static void controller_enter_draining(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = false;
    controller->drain_open = true;
    controller->state = CONTROLLER_STATE_DRAINING;
}

static void controller_enter_complete(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_COMPLETE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    uint32_t now_ms = input.now_ms;

    bool previous_filter_on = controller->filter_on;
    bool previous_drain_open = controller->drain_open;
    controller_state_t previous_state = controller->state;

    /* Process inputs */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = now_ms;
        break;

    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = now_ms;
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        /* Fall through to apply safe state */
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* No new input - check for sensor timeout */
        if (controller_has_both_sensors_valid(controller, now_ms)) {
            /* Sensors are still valid, continue with current state logic */
        } else {
            /* Sensor data is stale - go to safe idle */
            controller->has_valid_turbidity = false;
            controller->has_valid_level = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
        }
        break;
    }

    /* Apply state machine logic */
    bool both_sensors_valid = controller_has_both_sensors_valid(controller, now_ms);

    if (!both_sensors_valid) {
        /* Stay in safe idle until both sensors are valid */
        controller->filter_on = false;
        controller->drain_open = false;
        controller->state = CONTROLLER_STATE_SAFE_IDLE;
    } else if (input.kind == CONTROLLER_INPUT_NONE) {
        /* No new input - maintain current state but check for timeouts/disturbances */
        switch (controller->state) {
        case CONTROLLER_STATE_FILTERING:
            /* In filtering, just maintain state with no new turbidity processing */
            break;
        case CONTROLLER_STATE_SETTLING:
            /* Check for disturbance during settling even without new input */
            if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                controller_enter_filtering(controller, now_ms);
            } else if ((now_ms - controller->settling_started_ms) >= CONTROLLER_SETTLING_MS) {
                /* Settling complete - check for clear turbidity before draining */
                if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller_enter_draining(controller, now_ms);
                }
            }
            break;
        case CONTROLLER_STATE_DRAINING:
            /* Check for disturbance during draining even without new input */
            if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) {
                controller_enter_filtering(controller, now_ms);
            }
            break;
        case CONTROLLER_STATE_COMPLETE:
            /* Stay in complete until level recovers */
            if (!controller_is_level_below_complete_threshold(controller)) {
                controller_enter_filtering(controller, now_ms);
            }
            break;
        default:
            /* Safe idle or other states - maintain */
            break;
        }
    } else {
        /* Check for complete condition first (level too low) */
        if (controller_is_level_below_complete_threshold(controller)) {
            controller_enter_complete(controller);
        } else {
            /* We have sufficient level, process based on current state */
            switch (controller->state) {
            case CONTROLLER_STATE_SAFE_IDLE:
                /* Should not reach here if both_sensors_valid is true and level >= 15 */
                controller_enter_filtering(controller, now_ms);
                break;

            case CONTROLLER_STATE_FILTERING:
                /* Process turbidity for clear streak */
                if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller->clear_streak_count++;
                    if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                        controller_enter_settling(controller, now_ms);
                    }
                } else {
                    /* Turbidity went above threshold, reset streak */
                    controller->clear_streak_count = 0;
                }
                break;

            case CONTROLLER_STATE_SETTLING:
                /* Check for disturbance during settling */
                if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                    /* Disturbance detected - return to filtering */
                    controller_enter_filtering(controller, now_ms);
                } else if ((now_ms - controller->settling_started_ms) >= CONTROLLER_SETTLING_MS) {
                    /* Settling complete - check for clear turbidity before draining */
                    if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                        controller_enter_draining(controller, now_ms);
                    } else {
                        /* Still settling - wait for clear sample */
                        /* Keep filter off and drain closed */
                    }
                }
                break;

            case CONTROLLER_STATE_DRAINING:
                /* Check for disturbance during draining */
                if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) {
                    /* Disturbance detected - close drain and restart filtering */
                    controller_enter_filtering(controller, now_ms);
                }
                break;

            case CONTROLLER_STATE_COMPLETE:
                /* Stay in complete until level recovers or sensors become invalid */
                if (controller_is_level_sufficient(controller)) {
                    /* Level recovered - go back to filtering */
                    controller_enter_filtering(controller, now_ms);
                }
                break;

            default:
                controller_set_safe_idle(controller);
                break;
            }
        }
    }

    /* Update output */
    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_filter_on != controller->filter_on) ||
                     (previous_drain_open != controller->drain_open) ||
                     (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

